import React from 'react';
import styles from './Menu.module.css';
import classNames from 'classnames/bind';

const cx = classNames.bind(styles);

function Menu({menuType, onClick}) {
    const onTest = e => {
        debugger;
    };
    console.log('Menu.js: '+menuType);
    return (
        <ul>
          <li>
            <p 
                id="aboutme" onClick={() => onClick('aboutme')}
                className={cx({[menuType]: true})}>
              About Me
            </p>
          </li>
          <li>
              <p id="experience" onClick={() => onClick(menuType)}>
                Experience
              </p>
          </li>
          <li>
              <p id="projects" onClick={() => onClick(menuType)}>
                  Projects
              </p>
          </li>
          <li>
              <p id="skills" onClick={() => onClick(menuType)}>
                  Skills
              </p>
          </li>
          <li>
              <p id="photo" onClick={() => onClick(menuType)}>
                  Photo
              </p>
          </li>
        </ul>
    );
}

export default Menu;
